import org.apache.camel.spi.UriParams;

@UriParams
public class FixConfiguration implements Cloneable {

    @UriParam(label = "common")
    @Metadata(required = false)
    private String configFile;

    @UriParam(label = "common")
    @Metadata(required = false)
    private String senderCompID;

    @UriParam(label = "common")
    @Metadata(required = false)
    private String targetCompID;

    @UriParam(label = "common", defaultValue = "FIX.4.2")
    @Metadata(required = false)
    private String fixVersion = "FIX.4.2";

    @UriParam(label = "common", defaultValue = "30")
    @Metadata(required = false)
    private int heartBeatInterval = 30;

    @UriParam(label = "common")
    @Metadata(required = false)
    private String socketConnectHost;

    @UriParam(label = "common")
    @Metadata(required = false)
    private Integer socketConnectPort;

    public String getConfigFile() {
        return configFile;
    }

    public void setConfigFile(String configFile) {
        this.configFile = configFile;
    }

    public String getSenderCompID() {
        return senderCompID;
    }

    public void setSenderCompID(String senderCompID) {
        this.senderCompID = senderCompID;
    }

    public String getTargetCompID() {
        return targetCompID;
    }

    public void setTargetCompID(String targetCompID) {
        this.targetCompID = targetCompID;
    }

    public String getFixVersion() {
        return fixVersion;
    }

    public void setFixVersion(String fixVersion) {
        this.fixVersion = fixVersion;
    }

    public int getHeartBeatInterval() {
        return heartBeatInterval;
    }

    public void setHeartBeatInterval(int heartBeatInterval) {
        this.heartBeatInterval = heartBeatInterval;
    }

    public String getSocketConnectHost() {
        return socketConnectHost;
    }

    public void setSocketConnectHost(String socketConnectHost) {
        this.socketConnectHost = socketConnectHost;
    }

    public Integer getSocketConnectPort() {
        return socketConnectPort;
    }

    public void setSocketConnectPort(Integer socketConnectPort) {
        this.socketConnectPort = socketConnectPort;
    }

    @Override
    public FixConfiguration clone() throws CloneNotSupportedException {
        return (FixConfiguration) super.clone();
    }
}

