    25→/**
    26→ * The FIX producer sends outbound FIX messages from Camel exchanges.
    27→ */
    28→public class FixProducer extends DefaultAsyncProducer {
    29→    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);
    30→
    31→    private final FixEndpoint endpoint;
    32→    private final FixConfiguration configuration;
    33→
    34→    public FixProducer(FixEndpoint endpoint) {
    35→        super(endpoint);
    36→        this.endpoint = endpoint;
    37→        this.configuration = endpoint.getConfiguration();
    38→    }
    39→
    40→    @Override
    41→    public FixEndpoint getEndpoint() {
    42→        return (FixEndpoint) super.getEndpoint();
    43→    }
    44→
    45→    @Override
    46→    public boolean process(Exchange exchange, AsyncCallback callback) {
    47→        try {
    48→            String messageData = exchange.getIn().getBody(String.class);
    49→
    50→            LOG.debug("Sending FIX message: {}", messageData);
    51→
    52→            // Set response headers
    53→            exchange.getIn().setHeader(FixConstants.FIX_SESSION_ID,
    54→                configuration.getSenderCompID());
    55→
    56→            exchange.setProperty("fix.sent", true);
    57→            callback.done(true);
    58→        } catch (Exception e) {
    59→            exchange.setException(e);
    60→            callback.done(false);
    61→        }
    62→        return true;
    63→    }
    64→}
